const stylesheetCache = new Map<string, CSSStyleSheet>();

// Prepended to every component sheet so the HTML `[hidden]` attribute reliably
// hides elements even when an author rule sets `display: …` on the same node.
// Shadow DOM blocks the document-level UA `[hidden]` rule from being raised in
// specificity from outside, so we inject this once per sheet at the helper
// level — every shadow root that goes through `cssStyleSheet` gets it for free.
// See DLR #133.
const GLOBAL_PRELUDE = `[hidden]{display:none!important}`;

export function cssStyleSheet(cssText: string): CSSStyleSheet {
    // TODO: Remove this helper once Vite supports `import ... with { type: 'css' }`
    // as a real `CSSStyleSheet` export in both dev and build.
    const fullText = GLOBAL_PRELUDE + cssText;
    const cached = stylesheetCache.get(fullText);
    if (cached) {
        return cached;
    }

    const sheet = new CSSStyleSheet();
    sheet.replaceSync(fullText);
    stylesheetCache.set(fullText, sheet);
    return sheet;
}
